mapper.select:
SELECT m.medicine_id, m.name, m.specification, m.dosage_form, m.form, m.manufacturer, m.barcode, m.expiry_date, m.price, m.stock, m.warning_stock, m.warning_threshold, m.min_stock, m.unit, m.pharmacology, m.indications, m.dosage, m.side_effects, m.storage, m.status, m.is_prescription, m.category, m.location, m.create_by, m.create_time, m.update_by, m.update_time, m.remark FROM clinic_medicine m WHERE 1=1
AND (m.name LIKE CONCAT('%', #{name}, '%') OR m.manufacturer LIKE CONCAT('%', #{name}, '%'))
AND m.barcode = #{barcode}
AND m.dosage_form = #{dosageForm}
AND m.category = #{category}
AND m.status = #{status}
AND m.stock <= m.warning_stock

mapper.update:
UPDATE clinic_medicine
name = #{name}, specification = #{specification}, dosage_form = #{dosageForm}, form = #{form}, manufacturer = #{manufacturer}, barcode = #{barcode}, expiry_date = #{expiryDate}, price = #{price}, stock = #{stock}, warning_stock = #{warningStock}, warning_threshold = #{warningThreshold}, min_stock = #{minStock}, unit = #{unit}, pharmacology = #{pharmacology}, indications = #{indications}, dosage = #{dosage}, side_effects = #{sideEffects}, storage = #{storage}, status = #{status}, is_prescription = #{isPrescription}, category = #{category}, location = #{location}, remark = #{remark}, update_by = #{updateBy}, update_time = #{updateTime}
WHERE medicine_id = #{medicineId}

